1	import { QueryClient, QueryClientProvider } from '@tanstack/react-query';
2	import { useEffect, useState } from 'react';
3	import { RouterProvider } from 'react-router-dom';
4	import { Toaster } from 'sonner';
5	import { AuthReadyContext } from './ProtectedRoute';
6	import { router } from './router';
7	import { getMe } from '@/features/auth/authApi';
8	import { useAuthStore } from '@/store/useAuthStore';
9	import { useThemeStore } from '@/store/useThemeStore';
10	
11	const ThemeBootstrap = () => {
12	    const theme = useThemeStore((state) => state.theme);
13	
14	    useEffect(() => {
15	        document.documentElement.classList.toggle('dark', theme === 'dark');
16	    }, [theme]);
17	
18	    return null;
19	};
20	
21	const AuthBootstrap = ({ onReady }) => {
22	    const setUser = useAuthStore((state) => state.setUser);
23	    const logout = useAuthStore((state) => state.logout);
24	
25	    useEffect(() => {
26	        if (window.location.pathname === '/login') {
27	            onReady();
28	            return;
29	        }
30	
31	        let cancelled = false;
32	
33	        getMe()
34	            .then((user) => {
35	                if (!cancelled) {
36	                    setUser(user);
37	                    onReady();
38	                }
39	            })
40	            .catch(() => {
41	                if (!cancelled) {
42	                    logout();
43	                    onReady();
44	                }
45	            });
46	
47	        return () => {
48	            cancelled = true;
49	        };
50	    }, [logout, onReady, setUser]);
51	
52	    return null;
53	};
54	
55	export const Providers = () => {
56	    const [authReady, setAuthReady] = useState(false);
57	    const [queryClient] = useState(
58	        () =>
59	            new QueryClient({
60	                defaultOptions: {
61	                    queries: {
62	                        retry: 1,
63	                        staleTime: 1000 * 60 * 5,
64	                    },
65	                },
66	            }),
67	    );
68	
69	    return (
70	        <QueryClientProvider client={queryClient}>
71	            <ThemeBootstrap />
72	            <AuthBootstrap onReady={() => setAuthReady(true)} />
73	            <AuthReadyContext value={authReady}>
74	                <RouterProvider router={router} />
75	            </AuthReadyContext>
76	            <Toaster richColors position="top-right" />
77	        </QueryClientProvider>
78	    );
79	};
