1	import { createContext, use } from 'react';
2	import { Navigate, useLocation } from 'react-router-dom';
3	import { useAuthStore } from '@/store/useAuthStore';
4	
5	export const AuthReadyContext = createContext(false);
6	
7	export const ProtectedRoute = ({ children, ready = false }) => {
8	    const contextReady = use(AuthReadyContext);
9	    const isAuthenticated = useAuthStore((state) => state.isAuthenticated);
10	    const location = useLocation();
11	
12	    if (!(ready || contextReady)) {
13	        return null;
14	    }
15	
16	    if (!isAuthenticated) {
17	        return <Navigate to={`/login?returnUrl=${encodeURIComponent(location.pathname)}`} replace />;
18	    }
19	
20	    return children;
21	};
