1	import { zodResolver } from '@hookform/resolvers/zod';
2	import { useMutation } from '@tanstack/react-query';
3	import { useForm } from 'react-hook-form';
4	import { useNavigate, useSearchParams } from 'react-router-dom';
5	import { Button } from '@/shared/components/ui/button';
6	import { Input } from '@/shared/components/ui/input';
7	import { useAuthStore } from '@/store/useAuthStore';
8	import { login } from './authApi';
9	import { loginSchema } from './login.schema';
10	
11	const getSafeReturnUrl = (rawReturnUrl) => {
12	    if (typeof rawReturnUrl !== 'string') {
13	        return '/home';
14	    }
15	
16	    let decodedReturnUrl;
17	
18	    try {
19	        decodedReturnUrl = decodeURIComponent(rawReturnUrl);
20	    } catch {
21	        return '/home';
22	    }
23	
24	    if (
25	        !decodedReturnUrl.startsWith('/') ||
26	        decodedReturnUrl.startsWith('//') ||
27	        decodedReturnUrl.includes('://')
28	    ) {
29	        return '/home';
30	    }
31	
32	    return decodedReturnUrl;
33	};
34	
35	export const LoginPage = () => {
36	    const navigate = useNavigate();
37	    const [searchParams] = useSearchParams();
38	    const setUser = useAuthStore((state) => state.setUser);
39	    const returnUrl = getSafeReturnUrl(searchParams.get('returnUrl') || '/home');
40	    const {
41	        register,
42	        handleSubmit,
43	        formState: { errors },
44	    } = useForm({
45	        resolver: zodResolver(loginSchema),
46	        defaultValues: {
47	            username: '',
48	            password: '',
49	        },
50	    });
51	
52	    const mutation = useMutation({
53	        mutationFn: async (values) => {
54	            const data = await login(values);
55	
56	            if (!data?.user) {
57	                throw new Error('로그인 응답에 사용자 정보가 없습니다.');
58	            }
59	
60	            return data;
61	        },
62	        onSuccess: (data) => {
63	            setUser(data.user);
64	            navigate(returnUrl, { replace: true });
65	        },
66	    });
67	
68	    const usernameErrorId = errors.username ? 'login-username-error' : undefined;
69	    const passwordErrorId = errors.password ? 'login-password-error' : undefined;
70	    const mutationErrorId = mutation.isError ? 'login-form-error' : undefined;
71	    const mutationErrorMessage =
72	        mutation.error instanceof Error && mutation.error.message
73	            ? mutation.error.message
74	            : '로그인에 실패했습니다.';
75	
76	    return (
77	        <section className='w-full max-w-sm rounded-2xl border border-slate-200 bg-white p-8 shadow-xl shadow-slate-200/60 dark:border-slate-800 dark:bg-slate-950 dark:shadow-none'>
78	            <header className='mb-6 space-y-2'>
79	                <div className='mb-4 flex h-10 w-10 items-center justify-center rounded-xl bg-gradient-to-br from-blue-600 to-blue-400 text-base font-bold text-white shadow-sm'>
80	                    T
81	                </div>
82	                <h1 className='text-2xl font-semibold text-slate-900 dark:text-slate-100'>TrmWordDict</h1>
83	                <p className='text-sm text-slate-500 dark:text-slate-400'>단정한 용어 사전 시스템</p>
84	            </header>
85	            <form className='space-y-4' onSubmit={handleSubmit((values) => mutation.mutate(values))}>
86	                <div className='space-y-2'>
87	                    <label className='text-sm font-medium text-slate-700 dark:text-slate-300' htmlFor='username'>
88	                        아이디
89	                    </label>
90	                    <Input
91	                        id='username'
92	                        aria-describedby={usernameErrorId}
93	                        aria-invalid={errors.username ? 'true' : undefined}
94	                        autoComplete='username'
95	                        {...register('username')}
96	                    />
97	                    {errors.username ? (
98	                        <p
99	                            id={usernameErrorId}
100	                            role='alert'
101	                            className='text-sm text-rose-600 dark:text-rose-400'
102	                        >
103	                            {errors.username.message}
104	                        </p>
105	                    ) : null}
106	                </div>
107	                <div className='space-y-2'>
108	                    <label className='text-sm font-medium text-slate-700 dark:text-slate-300' htmlFor='password'>
109	                        비밀번호
110	                    </label>
111	                    <Input
112	                        id='password'
113	                        aria-describedby={passwordErrorId}
114	                        aria-invalid={errors.password ? 'true' : undefined}
115	                        autoComplete='current-password'
116	                        type='password'
117	                        {...register('password')}
118	                    />
119	                    {errors.password ? (
120	                        <p
121	                            id={passwordErrorId}
122	                            role='alert'
123	                            className='text-sm text-rose-600 dark:text-rose-400'
124	                        >
125	                            {errors.password.message}
126	                        </p>
127	                    ) : null}
128	                </div>
129	                {mutation.isError ? (
130	                    <p id={mutationErrorId} role='alert' className='text-sm text-rose-600 dark:text-rose-400'>
131	                        {mutationErrorMessage}
132	                    </p>
133	                ) : null}
134	                <Button className='w-full' type='submit' disabled={mutation.isPending}>
135	                    로그인
136	                </Button>
137	            </form>
138	        </section>
139	    );
140	};
