1	import axios from 'axios';
2	import { useAuthStore } from '../../store/useAuthStore';
3	
4	export const axiosInstance = axios.create({
5	    baseURL: '/api/v1',
6	    timeout: 30000,
7	    withCredentials: true,
8	    headers: {
9	        'Content-Type': 'application/json',
10	    },
11	});
12	
13	const AUTH_ERROR_CODE = 'AUTH_1002';
14	
15	const isUnauthorized = (status, code) => status === 401 || code === AUTH_ERROR_CODE;
16	
17	const expireServerSession = () =>
18	    axios.post('/api/v1/auth/logout', null, { withCredentials: true }).catch(() => {});
19	
20	const clearLocalSession = () => {
21	    useAuthStore.getState().logout();
22	};
23	
24	const handleUnauthorized = () => {
25	    // Global auth contract: any 401/AUTH_1002 response clears the local session and asks the server to expire the cookie.
26	    expireServerSession();
27	    clearLocalSession();
28	};
29	
30	axiosInstance.interceptors.response.use(
31	    (response) => response,
32	    (error) => {
33	        const status = error.response?.status;
34	        const code = error.response?.data?.code;
35	
36	        if (isUnauthorized(status, code)) {
37	            handleUnauthorized();
38	        }
39	
40	        return Promise.reject(error);
41	    }
42	);
43	
44	export const unwrapResponse = (response) => {
45	    const data = response?.data;
46	
47	    if (data === null || data === undefined) {
48	        throw new Error('요청 처리에 실패했습니다.');
49	    }
50	
51	    const isSuccess = data.success === true;
52	    const hasPayload = data.data !== null && data.data !== undefined;
53	
54	    if (!isSuccess || !hasPayload) {
55	        throw new Error(data.message ?? '요청 처리에 실패했습니다.');
56	    }
57	
58	    return data.data;
59	};
