71	const buildPageItems = (currentPage, totalPages) => {
72	    if (totalPages <= 1) {
73	        return [];
74	    }
75	
76	    if (totalPages <= MAX_VISIBLE_PAGES) {
77	        return Array.from({ length: totalPages }, (_, index) => ({ type: 'page', value: index + 1 }));
78	    }
79	
80	    const pages = new Set([1, totalPages, currentPage - 1, currentPage, currentPage + 1]);
81	    const ordered = [...pages]
82	        .filter((page) => page >= 1 && page <= totalPages)
83	        .sort((a, b) => a - b);
84	
85	    const items = [];
86	    let lastPage = 0;
87	
88	    ordered.forEach((page) => {
89	        if (page - lastPage > 1) {
90	            items.push({ type: 'ellipsis', key: `ellipsis-${lastPage}-${page}` });
91	        }
92	
93	        items.push({ type: 'page', value: page });
94	        lastPage = page;
95	    });
96	
97	    return items;
98	};
