1	import { axiosInstance, unwrapResponse } from '@/core/api/axiosInstance';
2	
3	export const emptyToNull = (value) => {
4	    const next = `${value ?? ''}`.trim();
5	    return next.length ? next : null;
6	};
7	
8	export const toSnakeCase = (value) => {
9	    if (value === null || value === undefined) {
10	        return '';
11	    }
12	
13	    return `${value}`.replace(/[A-Z]/g, (match) => `_${match.toLowerCase()}`);
14	};
15	
16	export async function requestJson({ method, url, data, signal }) {
17	    const response = await axiosInstance.request({
18	        method,
19	        url,
20	        data,
21	        signal,
22	    });
23	
24	    return unwrapResponse(response);
25	}
