3	export async function uploadCsv(type, file) {
4	    const formData = new FormData();
5	    formData.append('file', file);
6	
7	    const response = await axiosInstance.post('/imports', formData, {
8	        params: { type },
9	    });
10	
11	    return unwrapResponse(response);
12	}
13	
14	export async function getSummary(historyId) {
15	    const response = await axiosInstance.get(`/imports/${historyId}`);
16	    return unwrapResponse(response);
17	}
18	
19	export async function getErrorPage(historyId, page, size, sort) {
20	    const response = await axiosInstance.get(`/imports/${historyId}/errors`, {
21	        params: {
22	            page,
23	            size,
24	            sort,
25	        },
26	    });
27	
28	    return unwrapResponse(response);
29	}
